import React, { useCallback, useState } from 'react';
import {
  Button,
  LinCatalogUiSchemaEditorModal,
  dispatchAppToast,
  type CatalogUiSchema,
} from '@linm-soft/common-components';
import { masterCodePageLabels } from '../../../constants/masterCodePageLabels';
import { catalogUiSchemaService } from '../../../services/master/catalogUiSchemaService';
import { useAppDispatch } from '../../../store/hooks';
import { resolveApiErrorMessage } from '../../../utils/resolveApiErrorMessage';
import { CustomerCodeConfigModal } from '../masterCode/CustomerCodeConfigModal';
import { MasterCodeRegistrationModal } from '../masterCode/MasterCodeRegistrationModal';

const CUSTOMER_CATALOG_KIND = 'customers';

export interface CatalogUiSchemaEditorModalProps {
  testIdPrefix: string;
  catalogKind: string;
  isOpen: boolean;
  onClose: () => void;
  onSaved: (schema: CatalogUiSchema) => void;
  /**
   * Footer **Cấu hình mã danh mục**.
   * - `customers`: modal quy tắc nhóm L1 + cha (`CustomerGroupCodeHelper`).
   * - `AutoGenerate: true` (vd. `hr-employees`): `MasterCodeRegistrationModal`.
   */
  showMasterCodeConfig?: boolean;
}

export const CatalogUiSchemaEditorModal: React.FC<CatalogUiSchemaEditorModalProps> = ({
  testIdPrefix,
  catalogKind,
  isOpen,
  onClose,
  onSaved,
  showMasterCodeConfig = false,
}) => {
  const dispatch = useAppDispatch();
  const [masterCodeOpen, setMasterCodeOpen] = useState(false);

  const onError = useCallback((message: string) => {
    dispatchAppToast(dispatch, { message, type: 'error' });
  }, [dispatch]);

  const onSuccess = useCallback((message: string) => {
    dispatchAppToast(dispatch, { message, type: 'success' });
  }, [dispatch]);

  const resolveError = useCallback(
    (err: unknown, fallback: string) => resolveApiErrorMessage(err, fallback),
    [],
  );

  const footerExtraActions = showMasterCodeConfig ? (
    <Button
      variant="secondary"
      data-testid={`${testIdPrefix}-master-code-config`}
      onClick={() => setMasterCodeOpen(true)}
    >
      {masterCodePageLabels.configButton}
    </Button>
  ) : undefined;

  return (
    <>
      <LinCatalogUiSchemaEditorModal
        testIdPrefix={testIdPrefix}
        catalogKind={catalogKind}
        isOpen={isOpen}
        onClose={onClose}
        onSaved={onSaved}
        loadSchema={catalogUiSchemaService.get}
        saveSchema={catalogUiSchemaService.save}
        onError={onError}
        onSuccess={onSuccess}
        resolveErrorMessage={resolveError}
        footerExtraActions={footerExtraActions}
      />
      {showMasterCodeConfig && catalogKind === CUSTOMER_CATALOG_KIND ? (
        <CustomerCodeConfigModal
          testIdPrefix={`${testIdPrefix}-master-code`}
          isOpen={masterCodeOpen}
          onClose={() => setMasterCodeOpen(false)}
        />
      ) : null}
      {showMasterCodeConfig && catalogKind !== CUSTOMER_CATALOG_KIND ? (
        <MasterCodeRegistrationModal
          testIdPrefix={`${testIdPrefix}-master-code`}
          catalogKind={catalogKind}
          isOpen={masterCodeOpen}
          onClose={() => setMasterCodeOpen(false)}
        />
      ) : null}
    </>
  );
};
