import React, { useState } from 'react';
import { Button, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';

export interface CatalogListExportButtonProps {
  testIdPrefix: string;
  onExport: () => Promise<void>;
}

/** Toolbar «Xuất Excel» — client CSV (export-excel.md phase 2). */
export const CatalogListExportButton: React.FC<CatalogListExportButtonProps> = ({
  testIdPrefix,
  onExport,
}) => {
  const dispatch = useAppDispatch();
  const [exporting, setExporting] = useState(false);

  const handleExport = async () => {
    setExporting(true);
    try {
      await onExport();
      dispatchAppToast(dispatch, { message: 'Xuất file thành công', type: 'success' });
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Xuất file thất bại',
        type: 'error',
      });
    } finally {
      setExporting(false);
    }
  };

  return (
    <Button
      variant="secondary"
      size="sm"
      onClick={handleExport}
      disabled={exporting}
      data-testid={`${testIdPrefix}-export-btn`}
    >
      <i className="fas fa-file-excel" /> {exporting ? 'Đang xuất...' : 'Xuất Excel'}
    </Button>
  );
};
