import React, { useEffect, useState } from 'react';
import { Button, Input, Modal } from '@linm-soft/common-components';
import { useNavigate } from 'react-router-dom';
import {
  CUSTOMER_GROUP_ANALYSIS_ROWS,
  customerCodePageLabels,
} from '../../../constants/customerCodePageLabels';
import { masterService } from '../../../services/master/masterService';
import type { CustomerGroupDto } from '../../../services/master/models';
import { formatCustomerCodeExample } from '../../../utils/customerCodeFormat';
import { CUSTOMER_TYPE_LABELS } from '../../../utils/customerGroupTree';
import styles from './CustomerCodeConfigModal.module.css';

export interface CustomerCodeConfigModalProps {
  testIdPrefix: string;
  isOpen: boolean;
  onClose: () => void;
}

export const CustomerCodeConfigModal: React.FC<CustomerCodeConfigModalProps> = ({
  testIdPrefix,
  isOpen,
  onClose,
}) => {
  const navigate = useNavigate();
  const labels = customerCodePageLabels;
  const [loadingGroups, setLoadingGroups] = useState(false);
  const [level1Groups, setLevel1Groups] = useState<CustomerGroupDto[]>([]);

  useEffect(() => {
    if (!isOpen) return;
    let cancelled = false;
    setLoadingGroups(true);
    const t = setTimeout(() => {
      masterService
        .getCustomerGroups({ level: 1, page: 1, pageSize: 200, isActive: true })
        .then(res => {
          if (!cancelled) {
            setLevel1Groups(
              [...res.items].sort((a, b) => a.code.localeCompare(b.code, 'vi', { numeric: true })),
            );
          }
        })
        .catch(() => {
          if (!cancelled) setLevel1Groups([]);
        })
        .finally(() => {
          if (!cancelled) setLoadingGroups(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [isOpen]);

  const openCustomerGroups = () => {
    onClose();
    navigate('/dm/nhom-doi-tuong');
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={labels.modalTitle}
      size="lg"
      stacked
    >
      <div className={styles.body} data-testid={`${testIdPrefix}-customer-code-config`}>
        <p className={styles.intro}>{labels.intro}</p>

        <div className={styles.ruleBlock}>
          <p className={styles.ruleTitle}>{labels.ruleLevel1Title}</p>
          <p className={styles.ruleBody}>{labels.ruleLevel1Body}</p>
          <span className={styles.example}>{labels.exampleLevel1}</span>
        </div>

        <div className={styles.ruleBlock}>
          <p className={styles.ruleTitle}>{labels.ruleChildTitle}</p>
          <p className={styles.ruleBody}>{labels.ruleChildBody}</p>
          <span className={styles.example}>{labels.exampleChild}</span>
        </div>

        <div data-testid={`${testIdPrefix}-seq-padding`}>
          <Input
            label={labels.seqPaddingLabel}
            value={labels.seqPaddingValue}
            disabled
            fullWidth
          />
        </div>

        <div className={styles.section}>
          <p className={styles.sectionTitle}>{labels.analysisSectionTitle}</p>
          <p className={styles.sectionHint}>{labels.analysisSectionHint}</p>
          <div className={styles.tableWrap}>
            <table className={styles.table} data-testid={`${testIdPrefix}-analysis-table`}>
              <thead>
                <tr>
                  <th>{labels.analysisColType}</th>
                  <th>{labels.analysisColCode}</th>
                  <th>{labels.analysisColExampleFormat}</th>
                  <th>{labels.analysisColExampleCustomer}</th>
                </tr>
              </thead>
              <tbody>
                {CUSTOMER_GROUP_ANALYSIS_ROWS.map(row => (
                  <tr key={row.customerType}>
                    <td>{row.label}</td>
                    <td className={styles.mono}>{row.analysisCode}</td>
                    <td className={styles.mono}>{row.exampleFormatCode}</td>
                    <td className={styles.mono}>{row.exampleCustomerCode}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        <div className={styles.section}>
          <p className={styles.sectionTitle}>{labels.configuredSectionTitle}</p>
          {loadingGroups ? (
            <p className={styles.loadingHint}>
              <i className="fas fa-spinner fa-spin" /> {labels.configuredLoading}
            </p>
          ) : level1Groups.length === 0 ? (
            <p className={styles.emptyHint}>{labels.configuredEmpty}</p>
          ) : (
            <div className={styles.tableWrap}>
              <table className={styles.table} data-testid={`${testIdPrefix}-configured-table`}>
                <thead>
                  <tr>
                    <th>{labels.configuredColGroupCode}</th>
                    <th>{labels.configuredColName}</th>
                    <th>{labels.configuredColType}</th>
                    <th>{labels.configuredColFormat}</th>
                    <th>{labels.configuredColExample}</th>
                  </tr>
                </thead>
                <tbody>
                  {level1Groups.map(g => {
                    const formatCode = g.formatCode?.trim() || '—';
                    const example = g.formatCode?.trim()
                      ? formatCustomerCodeExample(g.formatCode, 1)
                      : '—';
                    const typeLabel = g.customerType
                      ? CUSTOMER_TYPE_LABELS[g.customerType] ?? g.customerType
                      : '—';
                    return (
                      <tr key={g.customerGroupId}>
                        <td className={styles.mono}>{g.code}</td>
                        <td>{g.name}</td>
                        <td>{typeLabel}</td>
                        <td className={styles.mono}>{formatCode}</td>
                        <td className={styles.mono}>{example}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>

        <p className={styles.hint}>{labels.formatCodeHint}</p>

        <div className={styles.footer}>
          <Button
            variant="secondary"
            onClick={openCustomerGroups}
            data-testid={`${testIdPrefix}-open-groups-btn`}
          >
            {labels.openGroupsButton}
          </Button>
          <Button variant="primary" onClick={onClose} data-testid={`${testIdPrefix}-close-btn`}>
            {labels.closeButton}
          </Button>
        </div>
      </div>
    </Modal>
  );
};
