import type { SelectOption } from '@linm-soft/common-components';

export function initOptionsToLabelMap(options: SelectOption[]): Map<string, string> {
  return new Map(options.map(o => [String(o.value), o.label]));
}

export function resolveInitOptionLabel(
  options: SelectOption[],
  value?: string | null,
  fallback = '',
): string {
  if (value == null || value === '') return fallback;
  const found = options.find(o => String(o.value) === value);
  return found?.label ?? value;
}
