import React, { useCallback, useMemo, useState } from 'react';
import type { CSSProperties } from 'react';
import type { ErpDataListGridProps } from '@linm-soft/common-components';
import { CatalogListGrid } from '../CatalogListGrid';
import { CatalogSchemaCell } from './CatalogSchemaCell';
import { resolveCatalogRowCellStyle } from './resolveCatalogRowCellStyle';
import type { CatalogUiField, CatalogUiSchema } from '../../../types/catalogUiSchema';
import type { UseCatalogListSelectionResult } from '../../../hooks/useCatalogListSelection';
import { catalogListTableConfigFromSchema } from '../catalogListTableConfig';
import {
  applyCatalogColumnFilters,
  applyCatalogColumnSort,
  catalogCellDisplayTextForKey,
} from '../../../utils/catalogListClientSearch';

export type ErpListSortState = { columnKey: string; direction: 'asc' | 'desc' } | null;

type CatalogListColumnListFlags = {
  showFilter?: boolean;
  allowSort?: boolean;
  width?: number | string;
};

type CatalogListGridFromSchemaBaseProps<T> = Pick<
  ErpDataListGridProps<T>,
  | 'getRowEditBlockedMessage'
  | 'rowEditHintDismissStorageKey'
  | 'onRowOpenActionMenu'
  | 'rowMenuHintMessage'
  | 'rowMenuHintDismissStorageKey'
  | 'enableRowMenuLongPress'
>;

type CatalogListGridFilterSortProps<T> = {
  filterSourceRows?: T[];
  getColumnDisplayValue?: (row: T, columnKey: string) => string;
  columnFilters?: Record<string, string[]>;
  onColumnFilterConfirm?: (columnKey: string, selectedValues: string[]) => void;
  onColumnFilterClear?: (columnKey: string) => void;
  sortState?: ErpListSortState;
  onSortChange?: (sort: ErpListSortState) => void;
};

export interface CatalogListGridFromSchemaProps<T>
  extends CatalogListGridFromSchemaBaseProps<T>, CatalogListGridFilterSortProps<T> {
  testIdPrefix: string;
  rows: T[];
  page: number;
  pageSize: number;
  columns: CatalogUiField[];
  schema?: CatalogUiSchema | null;
  selection: UseCatalogListSelectionResult<T>;
  getRowId: (row: T) => string;
  isRowSelectable?: (row: T) => boolean;
  /** When set, indents the code column: (depth - 1) * treeIndentPx. */
  getTreeRowDepth?: (row: T) => number;
  treeIndentPx?: number;
  /** Row cell colors — defaults to BE `fontColor` / `backgroundColor` on row. */
  getRowCellStyle?: (row: T) => CSSProperties | undefined;
}

export function CatalogListGridFromSchema<T>({
  testIdPrefix,
  rows,
  page,
  pageSize,
  columns,
  schema,
  selection,
  getRowId,
  isRowSelectable,
  getTreeRowDepth,
  treeIndentPx: indentStepPx = 16,
  getRowCellStyle,
  filterSourceRows,
  getColumnDisplayValue,
  columnFilters,
  onColumnFilterConfirm,
  onColumnFilterClear,
  sortState,
  onSortChange,
  getRowEditBlockedMessage,
  rowEditHintDismissStorageKey,
  onRowOpenActionMenu,
  rowMenuHintMessage,
  rowMenuHintDismissStorageKey,
  enableRowMenuLongPress,
}: CatalogListGridFromSchemaProps<T>): React.ReactElement {
  const columnDefs = columns.map(col => {
    const list = col.list as CatalogListColumnListFlags | undefined;
    return {
      key: col.key,
      label: col.label,
      width: list?.width,
      showFilter: list?.showFilter,
      allowSort: list?.allowSort,
    };
  });

  const resolveGetColumnDisplayValue = useCallback(
    (row: T, columnKey: string) => {
      if (getColumnDisplayValue) {
        return getColumnDisplayValue(row, columnKey);
      }
      return catalogCellDisplayTextForKey(
        row as unknown as Record<string, unknown>,
        columns,
        columnKey,
      );
    },
    [columns, getColumnDisplayValue],
  );

  const filterControlled =
    columnFilters !== undefined
    && onColumnFilterConfirm !== undefined
    && onColumnFilterClear !== undefined;

  const [internalColumnFilters, setInternalColumnFilters] = useState<Record<string, string[]>>({});
  const [internalSortState, setInternalSortState] = useState<ErpListSortState>(null);

  const effectiveColumnFilters = filterControlled ? columnFilters! : internalColumnFilters;
  const effectiveSortState = filterControlled ? (sortState ?? null) : internalSortState;

  const effectiveOnColumnFilterConfirm = useCallback(
    (columnKey: string, selectedValues: string[]) => {
      if (onColumnFilterConfirm) {
        onColumnFilterConfirm(columnKey, selectedValues);
        return;
      }
      setInternalColumnFilters(prev => ({ ...prev, [columnKey]: selectedValues }));
    },
    [onColumnFilterConfirm],
  );

  const effectiveOnColumnFilterClear = useCallback(
    (columnKey: string) => {
      if (onColumnFilterClear) {
        onColumnFilterClear(columnKey);
        return;
      }
      setInternalColumnFilters(prev => {
        const next = { ...prev };
        delete next[columnKey];
        return next;
      });
    },
    [onColumnFilterClear],
  );

  const effectiveOnSortChange = useCallback(
    (sort: ErpListSortState) => {
      if (onSortChange) {
        onSortChange(sort);
        return;
      }
      setInternalSortState(sort);
    },
    [onSortChange],
  );

  const filterRows = filterSourceRows ?? rows;

  const displayRows = useMemo(() => {
    if (filterControlled) return rows;
    const filtered = applyCatalogColumnFilters(
      rows as unknown as Record<string, unknown>[],
      columns,
      effectiveColumnFilters,
    );
    return applyCatalogColumnSort(filtered, columns, effectiveSortState) as T[];
  }, [columns, effectiveColumnFilters, effectiveSortState, filterControlled, rows]);

  const resolveRowStyle = (row: T): CSSProperties | undefined =>
    getRowCellStyle?.(row)
    ?? resolveCatalogRowCellStyle(row as unknown as Record<string, unknown>);

  const gridProps = {
    testIdPrefix,
    rows: displayRows,
    page,
    pageSize,
    selection,
    getRowId,
    isRowSelectable,
    getRowEditBlockedMessage,
    rowEditHintDismissStorageKey,
    onRowOpenActionMenu,
    rowMenuHintMessage,
    rowMenuHintDismissStorageKey,
    enableRowMenuLongPress,
    filterSourceRows: filterRows,
    getColumnDisplayValue: resolveGetColumnDisplayValue,
    columnFilters: effectiveColumnFilters,
    onColumnFilterConfirm: effectiveOnColumnFilterConfirm,
    onColumnFilterClear: effectiveOnColumnFilterClear,
    sortState: effectiveSortState,
    onSortChange: effectiveOnSortChange,
    columnDefs,
    tableConfig: catalogListTableConfigFromSchema(schema?.list),
    headerCells: (
      <>
        {columns.map(col => (
          <th key={col.key}>{col.label}</th>
        ))}
      </>
    ),
    renderRow: (row: T) => {
      const treeDepth = getTreeRowDepth?.(row);
      const codeIndentPx =
        treeDepth != null && treeDepth > 1
          ? Math.max(0, treeDepth - 1) * indentStepPx
          : undefined;
      const cellStyle = resolveRowStyle(row);
      return (
        <>
          {columns.map(col => (
            <CatalogSchemaCell
              key={col.key}
              field={col}
              row={row as unknown as Record<string, unknown>}
              testIdPrefix={testIdPrefix}
              codeIndentPx={col.key === 'code' ? codeIndentPx : undefined}
              cellStyle={cellStyle}
              displayText={resolveGetColumnDisplayValue(row, col.key)}
            />
          ))}
        </>
      );
    },
  } as ErpDataListGridProps<T>;

  return <CatalogListGrid {...gridProps} />;
}

export type ErpListColumnFilters = Record<string, string[]>;
