import type { SearchInputConfig } from '@linm-soft/common-components';
import { masterService } from '../../services/master/masterService';
import type { CustomerDto } from '../../services/master/models';

export type CustomerSearchType = 'Customer' | 'Supplier' | 'Both';

export interface CreateCustomerSearchConfigOptions {
  customerType?: CustomerSearchType;
  /** Loại trừ bản ghi đang sửa — không chọn làm đối tượng cha của chính nó. */
  excludeCustomerId?: string;
}

/** SEARCH_REMOTE — danh mục đối tượng (`GET /master/customers`). */
export function createCustomerSearchConfig(
  options: CreateCustomerSearchConfigOptions = {},
): SearchInputConfig<CustomerDto> {
  const { customerType, excludeCustomerId } = options;

  return {
    api: {
      getItemKey: c => c.customerId,
      search: async ({ search, page, pageSize }) => {
        const res = await masterService.getCustomers({
          search: search?.trim() || undefined,
          page,
          pageSize,
          customerType,
          isActive: true,
        });
        const items = excludeCustomerId
          ? res.items.filter(c => c.customerId !== excludeCustomerId)
          : res.items;
        const totalPages = Math.max(1, Math.ceil(res.totalCount / pageSize));
        return { items, page: res.page, totalPages };
      },
    },
    display: {
      getPrimaryDisplay: c => c.code,
      getSecondaryDisplay: c => c.name,
      getSingleDisplay: c => `${c.code} — ${c.name}`,
    },
    columns: [
      { key: 'code', variant: 'badge', width: '6rem', render: c => c.code },
      { key: 'name', variant: 'primary', render: c => c.name },
      {
        key: 'phone',
        variant: 'meta',
        width: '7rem',
        visible: c => !!c.phone,
        render: c => c.phone ?? '',
      },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã' },
        { key: 'name', label: 'Tên đối tượng' },
        { key: 'phone', label: 'Điện thoại' },
      ],
    },
    texts: { empty: 'Không tìm thấy đối tượng' },
    dropdownPortal: true,
    dropdownMatch: 'row',
    dropdownMinWidth: '22rem',
  };
}
