import type { SearchInputConfig } from '@linm-soft/common-components';
import { masterService } from '../../services/master/masterService';
import type { SupplierContractDto } from '../../services/master/models';

/** Lookup hợp đồng NCC theo đối tượng (`GET /master/customers/:id/supplier-contracts`). */
export function createSupplierContractSearchConfig(
  supplierCustomerId: string,
): SearchInputConfig<SupplierContractDto> {
  return {
    api: {
      getItemKey: c => c.id,
      search: async ({ search }) => {
        const items = await masterService.getSupplierContracts(
          supplierCustomerId,
          search?.trim() || undefined,
        );
        return { items, page: 1, totalPages: 1 };
      },
    },
    display: {
      getPrimaryDisplay: c => c.contractNumber,
      getSecondaryDisplay: c => c.code,
      getSingleDisplay: c => c.contractNumber,
    },
    columns: [
      { key: 'contractNumber', variant: 'badge', width: '8rem', render: c => c.contractNumber },
      { key: 'contractDate', variant: 'meta', width: '6rem', render: c => c.contractDate?.slice(0, 10) ?? '' },
    ],
    header: {
      columns: [
        { key: 'contractNumber', label: 'Số HĐ' },
        { key: 'contractDate', label: 'Ngày ký' },
      ],
    },
    texts: { empty: 'Không tìm thấy hợp đồng — nhập số HĐ mới để tạo khi Lưu' },
  };
}
